export type RedactionAction = "mask" | "replace" | "remove";
export type ScanMode = "balanced" | "strict";

export interface SensitiveEntity {
  id: string;
  type: string;
  start: number;
  end: number;
  text: string;
  reason: string;
  replacement: string;
