def _ok(payload: dict[str, Any], status_code: int = 200) -> tuple[int, dict[str, Any]]:
    body = _base_payload()
    body.update(payload)
    body["ok"] = True
    return status_code, body


def _error_payload(message: str, *, status_code: int, error_type: str = "error") -> tuple[int, dict[str, Any]]:
    body = _base_payload()
    body.update({"ok": False, "error": message, "error_type": error_type})
    return status_code, body


def _decode_audio_base64(data: str) -> bytes:
    if not data:
        raise ApiError("No audio payload provided.", status_code=400)
    payload = data.split(",", 1)[1] if data.startswith("data:") and "," in data else data
    try:
        return base64.b64decode(payload, validate=True)
    except Exception as exc:
        raise ApiError("audio_base64 is not valid base64 data.", status_code=400) from exc


def _encode_wav_data_url(audio: Any, sample_rate: int) -> str | None:
    if np is None:
        return None

    arr = np.asarray(audio, dtype=np.float32)
    if arr.ndim != 1:
        arr = np.ravel(arr)
    if arr.size == 0:
        return None

    clipped = np.clip(arr, -1.0, 1.0)
    pcm16 = (clipped * 32767.0).astype(np.int16)

    buffer = io.BytesIO()
    with wave.open(buffer, "wb") as wav_file:
        wav_file.setnchannels(1)
        wav_file.setsampwidth(2)
        wav_file.setframerate(int(sample_rate))
        wav_file.writeframes(pcm16.tobytes())

    encoded = base64.b64encode(buffer.getvalue()).decode("ascii")
    return f"data:audio/wav;base64,{encoded}"


