def add_background_noise(
    audio: Any,
    sr: int,
    *,
    snr_db: float = 10.0,
    noise_type: str = "office",
) -> "np.ndarray":
    """Mix synthetic ambient noise at the requested SNR."""
    _require_audio_stack()
    source = _normalize(audio)
    noise = _generate_ambient_noise(source.shape[0], sr, noise_type=noise_type)
    signal_power = float(np.mean(source**2)) + 1e-10
    noise_power = float(np.mean(noise**2)) + 1e-10
    desired_noise_power = signal_power / (10 ** (snr_db / 10.0))
    scale = float(np.sqrt(desired_noise_power / noise_power))
    mixed = source + noise * scale
    return _normalize(mixed)


def simulate_phone(audio: Any, sr: int) -> "np.ndarray":
    """Band-limit the signal to telephone speech bandwidth."""
    _require_audio_stack()
    source = _normalize(audio)
    band_limited = _butter_filter(source, sr, low_hz=300.0, high_hz=3400.0, order=5)
    if lfilter is not None:
        band_limited = lfilter([1.0, -0.92], [1.0], band_limited).astype(np.float32)
    return _normalize(band_limited)


def apply_augmentation(audio: Any, sr: int, augmentation_type: str, **kwargs: Any) -> tuple["np.ndarray", dict[str, Any]]:
    key = (augmentation_type or "clean").strip().lower().replace("-", "_").replace(" ", "_")

    if key in {"clean", "none"}:
        return _normalize(audio), {
            "type": "clean",
            "label": "Clean",
            "description": "No augmentation applied.",
        }

    if key in {"cold", "simulate_cold", "cold_sore_throat"}:
        return simulate_cold(audio, sr), {
            "type": "cold",

if key in {"cold", "simulate_cold", "cold_sore_throat"}:
        return simulate_cold(audio, sr), {
            "type": "cold",
            "label": "Simulate Cold/Sore Throat",
            "description": "Pitch shift, jitter, and mild breathiness.",
        }

    if key in {"accent", "simulate_accent", "different_accent"}:
        return simulate_accent(audio, sr), {
            "type": "accent",
            "label": "Simulate Different Accent",
            "description": "Subtle speaking-rate and spectral-tilt perturbation.",
        }

    if key in {"noise", "add_noise", "background_noise"}:
        snr_db = float(kwargs.get("snr_db", 10.0))
        noise_type = str(kwargs.get("noise_type", "office"))
        return add_background_noise(audio, sr, snr_db=snr_db, noise_type=noise_type), {
            "type": "noise",
            "label": "Add Background Noise",
            "description": f"Synthetic {noise_type} ambience mixed at {snr_db:.1f} dB SNR.",
            "snr_db": snr_db,
            "noise_type": noise_type,
        }

    if key in {"phone", "simulate_phone", "phone_call_quality"}:
        return simulate_phone(audio, sr), {
            "type": "phone",
            "label": "Simulate Phone Call Quality",
            "description": "Telephony-style 300-3400 Hz bandpass filtering.",
        }

    supported = ", ".join(sorted(available_augmentations().keys()))
    raise AugmentationError(f"Unknown augmentation '{augmentation_type}'. Supported types: {supported}.")


